class Solution:
    def getMaxRepetitions(self, s1: str, n1: int, s2: str, n2: int) -> int:
        if not s1 or not s2 or n1 == 0 or n2 == 0:
            return 0
        j = 0
        count = 0
        repeatCount = [0] * (len(s1) + 1)
        nextIndex = [0] * (len(s1) + 1)
        for k in range(1, n1 + 1):
            for i in range(len(s1)):
                if s1[i] == s2[j]:
                    j += 1
                    if j == len(s2):
                        count += 1
                        j = 0
            repeatCount[k] = count
            nextIndex[k] = j
            for start in range(k):
                if nextIndex[start] == j:
                    prefixCount = repeatCount[start]
                    patternCount = (repeatCount[k] - repeatCount[start]) * ((n1 - start) // (k - start))
                    suffixCount = repeatCount[start + (n1 - start) % (k - start)] - repeatCount[start]
                    return (prefixCount + patternCount + suffixCount) // n2
        return repeatCount[n1] // n2
